import{_ as e,o as t,c as n,ae as a}from"./chunks/framework.DfCsusKa.js";const f=JSON.parse('{"title":"推薦 RSS 與新聞源列表","description":"","frontmatter":{},"headers":[],"relativePath":"AI_notice/follow_list.md","filePath":"AI_notice/follow_list.md"}'),o={name:"AI_notice/follow_list.md"};function s(l,r,g,i,h,c){return t(),n("div",null,[...r[0]||(r[0]=[a('<h1 id="推薦-rss-與新聞源列表" tabindex="-1">推薦 RSS 與新聞源列表 <a class="header-anchor" href="#推薦-rss-與新聞源列表" aria-label="Permalink to &quot;推薦 RSS 與新聞源列表&quot;">​</a></h1><h2 id="🔬-深度技術與論文-技術前沿" tabindex="-1">🔬 深度技術與論文 (技術前沿) <a class="header-anchor" href="#🔬-深度技術與論文-技術前沿" aria-label="Permalink to &quot;🔬 深度技術與論文 (技術前沿)&quot;">​</a></h2><ul><li><p><strong>Hugging Face Blog</strong>: <a href="https://huggingface.co/blog/feed.xml" target="_blank" rel="noreferrer">RSS</a><br><strong>內容概述</strong>: Hugging Face 官方博客，分享開源 AI 模型、Transformer 架構、NLP 和 CV 技術更新，以及實作教程。<br><strong>推薦原因</strong>: 最新的 Open Source 模型趨勢與技術實作，適合工程師學習和應用最新工具。</p></li><li><p><strong>arXiv.org (CS.LG/AI)</strong>: <a href="https://arxiv.org/rss/cs.AI" target="_blank" rel="noreferrer">RSS</a> 或 <a href="https://arxiv.org/rss/cs.LG" target="_blank" rel="noreferrer">CS.LG</a><br><strong>內容概述</strong>: 機器學習和人工智慧領域的學術論文預印本平台，每天有大量新論文上傳，涵蓋理論、算法和應用。<br><strong>推薦原因</strong>: 機器學習與人工智慧的學術源頭（雖然量大，但標題掃描很重要），幫助跟上前沿研究。</p></li><li><p><strong>Google Research Blog</strong>: <a href="https://research.googleblog.com/feeds/posts/default" target="_blank" rel="noreferrer">RSS</a><br><strong>內容概述</strong>: Google 研究團隊的技術博客，介紹 AI、機器學習、深度學習等領域的最新研究成果和技術進展。<br><strong>推薦原因</strong>: 了解你目前使用的 Gemini 等 Google AI 產品的核心技術演進，深入技術細節。</p></li></ul><h2 id="🛠️-開發者與工具-軟體工具" tabindex="-1">🛠️ 開發者與工具 (軟體工具) <a class="header-anchor" href="#🛠️-開發者與工具-軟體工具" aria-label="Permalink to &quot;🛠️ 開發者與工具 (軟體工具)&quot;">​</a></h2><ul><li><p><strong>VentureBeat AI Section</strong>: <a href="https://venturebeat.com/ai/" target="_blank" rel="noreferrer">Link</a><br><strong>內容概述</strong>: VentureBeat 的 AI 專欄，報導 AI 技術在企業、開發工具和應用場景中的最新動態和趨勢。<br><strong>推薦原因</strong>: 產業界對 AI 工具應用的報導非常迅速，適合開發者了解市場應用和工具更新。</p></li><li><p><strong>The Batch (DeepLearning.AI)</strong>: <a href="https://www.deeplearning.ai/the-batch/" target="_blank" rel="noreferrer">Link</a><br><strong>內容概述</strong>: DeepLearning.AI 的免費新聞摘要，由 Andrew Ng 團隊編輯，涵蓋 AI 研究、新聞和實用見解。<br><strong>推薦原因</strong>: 吳恩達團隊整理的新聞，觀點中肯且具技術底蘊，適合工程師獲取高品質資訊。</p></li><li><p><strong>GitHub Trending (Python/AI)</strong>: <a href="https://github.com/trending/python?since=daily" target="_blank" rel="noreferrer">Link</a> 或 <a href="https://github.com/trending?since=daily&amp;spoken_language_code=en&amp;q=ai" target="_blank" rel="noreferrer">AI 相關</a><br><strong>內容概述</strong>: GitHub 上每日/每週最受歡迎的 Python 和 AI 相關開源倉庫，展示熱門項目和趨勢。<br><strong>推薦原因</strong>: 雖然不是 RSS，但每天看一眼可以知道現在最火的 Agent 框架、模型庫等，幫助發現新工具。</p></li></ul><h2 id="⚡-產業與硬體-硬體產業" tabindex="-1">⚡ 產業與硬體 (硬體產業) <a class="header-anchor" href="#⚡-產業與硬體-硬體產業" aria-label="Permalink to &quot;⚡ 產業與硬體 (硬體產業)&quot;">​</a></h2><ul><li><p><strong>SemiAnalysis</strong>: <a href="https://semianalysis.com/" target="_blank" rel="noreferrer">Link</a><br><strong>內容概述</strong>: 專注於半導體和 AI 晶片的深度分析網站，提供供應鏈、晶片架構和算力趨勢的專業報告。<br><strong>推薦原因</strong>: 深度分析 AI 晶片、供應鏈與算力佈局，資訊量極大，適合硬體和系統工程師。</p></li><li><p><strong>TechCrunch AI</strong>: <a href="https://techcrunch.com/tag/artificial-intelligence/feed/" target="_blank" rel="noreferrer">RSS</a><br><strong>內容概述</strong>: TechCrunch 的 AI 標籤頁面，報導 AI 新創公司、投資融資、商業模式和技術突破。<br><strong>推薦原因</strong>: 追蹤 AI 新創公司的募資與商業模式，了解產業動態和投資機會。</p></li></ul>',7)])])}const b=e(o,[["render",s]]);export{f as __pageData,b as default};
